function isLinuxPlatform(osLower: string, platformLower: string): boolean {
  if (osLower.includes("linux")) return true;

  const linuxMarkers = [
    "ubuntu",
    "debian",
    "mint",
    "pop",
    "kali",
    "raspbian",
    "raspberry",
    "fedora",
    "rhel",
    "red hat",
    "centos",
    "rocky",
    "alma",
    "oracle",
    "arch",
    "manjaro",
    "endeavour",
    "suse",
    "opensuse",
    "sles",
    "alpine",
    "gentoo",
    "void",
    "nixos",
    "slackware",
    "clear",
    "photon",
    "amazon linux",
    "amzn",
    "proxmox",
  ];

  return linuxMarkers.some(
    (marker) => platformLower.includes(marker) || osLower.includes(marker)
  );
}

export function OSIcon({
  os,
  platform,
  size = 16,
}: {
  os: string;
  platform: string;
  size?: number;
}) {
  const osLower = (os ?? "").toLowerCase();
  const platformLower = (platform ?? "").toLowerCase();

  if (osLower.includes("windows")) {
    if (/windows server/i.test(os)) return <WindowsServerIcon size={size} />;
    if (/windows (95|98|me|nt\s*4|2000)/i.test(os)) return <WindowsClassicIcon size={size} />;
    if (/windows (xp|vista|7\b|2003|2008)/i.test(os)) return <WindowsClassicIcon size={size} />;
    return <WindowsModernIcon size={size} />;
  }

  if (
    osLower.includes("darwin") ||
    osLower.includes("macos") ||
    osLower.includes("os x") ||
    platformLower === "darwin" ||
    platformLower.includes("macos")
  ) {
    return <MacOSIcon size={size} />;
  }

  if (platformLower.includes("opnsense") || osLower.includes("opnsense")) {
    return <OPNsenseIcon size={size} />;
  }
  if (platformLower.includes("pfsense") || osLower.includes("pfsense")) {
    return <PfSenseIcon size={size} />;
  }

  if (osLower.includes("freebsd") || platformLower.includes("freebsd")) return <FreeBSDIcon size={size} />;
  if (osLower.includes("openbsd") || platformLower.includes("openbsd")) return <OpenBSDIcon size={size} />;
  if (osLower.includes("netbsd") || platformLower.includes("netbsd")) return <NetBSDIcon size={size} />;

  if (osLower.includes("proxmox") || platformLower.includes("proxmox")) return <ProxmoxIcon size={size} />;

  if (isLinuxPlatform(osLower, platformLower)) {
    if (platformLower.includes("ubuntu")) return <UbuntuIcon size={size} />;
    if (platformLower.includes("debian")) return <DebianIcon size={size} />;
    if (platformLower.includes("mint")) return <MintIcon size={size} />;
    if (platformLower.includes("raspbian") || platformLower.includes("raspberry")) return <RaspbianIcon size={size} />;
    if (platformLower.includes("pop")) return <PopOSIcon size={size} />;
    if (platformLower.includes("kali")) return <KaliIcon size={size} />;
    if (platformLower.includes("rhel") || platformLower.includes("red hat") || platformLower.includes("redhat")) return <RHELIcon size={size} />;
    if (platformLower.includes("fedora")) return <FedoraIcon size={size} />;
    if (platformLower.includes("centos")) return <CentOSIcon size={size} />;
    if (platformLower.includes("rocky")) return <RockyIcon size={size} />;
    if (platformLower.includes("alma")) return <AlmaIcon size={size} />;
    if (platformLower.includes("manjaro")) return <ManjaroIcon size={size} />;
    if (platformLower.includes("endeavour")) return <EndeavourIcon size={size} />;
    if (platformLower.includes("arch")) return <ArchIcon size={size} />;
    if (platformLower.includes("opensuse") || platformLower.includes("suse") || platformLower.includes("sles")) return <SUSEIcon size={size} />;
    if (platformLower.includes("alpine")) return <AlpineIcon size={size} />;
    if (platformLower.includes("gentoo")) return <GentooIcon size={size} />;
    if (platformLower.includes("void")) return <VoidIcon size={size} />;
    if (platformLower.includes("nixos")) return <NixOSIcon size={size} />;
    if (platformLower.includes("slackware")) return <SlackwareIcon size={size} />;
    return <LinuxIcon size={size} />;
  }

  return <GenericIcon size={size} />;
}
